import{_ as t,o as a,c as r,ae as s}from"./chunks/framework.Czhw_PXq.js";const i="/images/architecture.png",g=JSON.parse('{"title":"Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/architecture.md","filePath":"getting-started/architecture.md"}'),o={name:"getting-started/architecture.md"};function n(c,e,d,l,h,p){return a(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h1><h2 id="system-overview" tabindex="-1">System Overview <a class="header-anchor" href="#system-overview" aria-label="Permalink to &quot;System Overview&quot;">​</a></h2><p><img src="'+i+`" alt="Architecture"></p><p><strong>External services:</strong> Authup (OAuth2), Redis (pub/sub + caching), MySQL/PostgreSQL</p><h2 id="hexagonal-architecture" tabindex="-1">Hexagonal Architecture <a class="header-anchor" href="#hexagonal-architecture" aria-label="Permalink to &quot;Hexagonal Architecture&quot;">​</a></h2><p>All services follow a <strong>hexagonal (ports &amp; adapters)</strong> architecture with three layers:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>src/</span></span>
<span class="line"><span>├── core/          # Domain logic — ports, services, validators</span></span>
<span class="line"><span>├── adapters/      # External system implementations — database, HTTP, socket</span></span>
<span class="line"><span>└── app/           # Orchestration — DI modules, wiring, factory</span></span></code></pre></div><h3 id="core-layer" tabindex="-1">Core Layer <a class="header-anchor" href="#core-layer" aria-label="Permalink to &quot;Core Layer&quot;">​</a></h3><p>Pure business logic with no infrastructure imports. Contains:</p><ul><li><strong>Entity services</strong> — own validation, receive repositories via constructor injection</li><li><strong>Port interfaces</strong> — <code>IXRepository</code>, <code>IXService</code> abstractions</li><li><strong>Business services</strong> — orchestrate workflows across multiple entities</li><li><strong>Validators</strong> — input validation using Zod schemas</li></ul><h3 id="adapter-layer" tabindex="-1">Adapter Layer <a class="header-anchor" href="#adapter-layer" aria-label="Permalink to &quot;Adapter Layer&quot;">​</a></h3><p>Implementations that connect domain logic to external systems:</p><ul><li><strong>Database</strong> — TypeORM entity definitions, subscribers, migrations</li><li><strong>HTTP</strong> — thin controllers that extract requests, delegate to services, and send responses</li><li><strong>Socket</strong> — WebSocket handlers</li></ul><h3 id="app-layer" tabindex="-1">App Layer <a class="header-anchor" href="#app-layer" aria-label="Permalink to &quot;App Layer&quot;">​</a></h3><p>DI modules, wiring, and infrastructure services:</p><ul><li><strong>Modules</strong> — each implements <code>IModule</code> from orkos (config, database, HTTP, etc.)</li><li><strong>Builder</strong> — fluent API for assembling the application</li><li><strong>Factory</strong> — <code>createApplication()</code> entry point</li></ul><h2 id="authentication" tabindex="-1">Authentication <a class="header-anchor" href="#authentication" aria-label="Permalink to &quot;Authentication&quot;">​</a></h2><p>All services integrate with <strong>Authup</strong> (OAuth2 identity provider):</p><ul><li>Token validation via <code>@authup/server-adapter</code> middleware</li><li>Per-realm permission checks via <code>@authup/access</code></li><li>Two-phase permission model: <code>preCheck</code> (fast fail) then <code>check</code> (with policy attributes)</li></ul><h2 id="domain-events-messaging" tabindex="-1">Domain Events &amp; Messaging <a class="header-anchor" href="#domain-events-messaging" aria-label="Permalink to &quot;Domain Events &amp; Messaging&quot;">​</a></h2><p>TypeORM subscribers publish domain events via Redis pub/sub and AMQP (RabbitMQ). AMQP consumers are wired through DI modules:</p><ul><li><strong>Aggregators</strong> — react to events from other services</li><li><strong>Components</strong> — task consumer workers for background processing</li></ul><h2 id="key-domain-entities" tabindex="-1">Key Domain Entities <a class="header-anchor" href="#key-domain-entities" aria-label="Permalink to &quot;Key Domain Entities&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Entity</th><th>Purpose</th></tr></thead><tbody><tr><td><code>Analysis</code></td><td>A distributed computation task</td></tr><tr><td><code>AnalysisBucket</code></td><td>File storage container for an analysis</td></tr><tr><td><code>Project</code></td><td>User project grouping nodes and analyses</td></tr><tr><td><code>ProjectNode</code></td><td>A compute node assigned to a project</td></tr><tr><td><code>Node</code></td><td>Global registry of available compute nodes</td></tr><tr><td><code>MasterImage</code></td><td>Base Docker images for worker tasks</td></tr><tr><td><code>Registry</code></td><td>Docker registry configuration</td></tr><tr><td><code>RegistryProject</code></td><td>Project within a Docker registry</td></tr></tbody></table>`,24)])])}const m=t(o,[["render",n]]);export{g as __pageData,m as default};
